// ════════════════════════════════════════════════════════
// TOOL: CONSULTAR CLIENTE
// Busca cliente pelo telefone na organização
// ════════════════════════════════════════════════════════

const input = $input.item.json;
const query = input.query || '';
const organizacaoId = input.organizacao_id || input.organizacaoId;
const telefoneLimpo = input.telefone_limpo || input.telefone || '';
const remoteJid = input.remote_jid || input.remetente_numero || '';

// Extrair telefone do query se não veio direto
let telefone = telefoneLimpo;
if (!telefone && query) {
  // Tentar extrair números do query
  const nums = query.replace(/[^0-9]/g, '');
  if (nums.length >= 10) {
    telefone = nums;
  }
}

// Também tentar extrair do remoteJid
if (!telefone && remoteJid) {
  telefone = remoteJid.replace('@s.whatsapp.net', '').replace('@c.us', '');
}

if (!telefone) {
  return [{ json: { error: true, message: 'Telefone não informado. Não é possível consultar o cliente.' } }];
}

if (!organizacaoId) {
  return [{ json: { error: true, message: 'organizacao_id não informado.' } }];
}

return [{
  json: {
    telefone: telefone,
    organizacao_id: organizacaoId
  }
}];

// Formatar resposta
const resultado = $input.item.json;

if (resultado && resultado.cliente_id) {
  return [{
    json: {
      response: JSON.stringify({
        encontrado: true,
        cliente_id: resultado.cliente_id,
        nome: resultado.nome
      }),
      success: true
    }
  }];
} else {
  return [{
    json: {
      response: JSON.stringify({
        encontrado: false,
        mensagem: 'Cliente não encontrado com este telefone. Pergunte se deseja se cadastrar.'
      }),
      success: true
    }
  }];
}
